/// <reference lib="webworker" />
// This service worker can be customized!
// See https://developers.google.com/web/tools/workbox/modules
// for the list of available Workbox modules, or add any other
// code you'd like.
// You can also remove this file if you'd prefer not to use a
// service worker, and the Workbox build step will be skipped.
import { clientsClaim } from 'workbox-core'
import { ExpirationPlugin } from 'workbox-expiration'
import { createHandlerBoundToURL, precacheAndRoute } from 'workbox-precaching'
import { registerRoute } from 'workbox-routing'
import { StaleWhileRevalidate } from 'workbox-strategies'

declare const self: ServiceWorkerGlobalScope
declare const __APP_VERSION__: string

// Take control of all clients immediately
clientsClaim()

// Precache all of the assets generated by your build process.
// Their URLs are injected into the manifest variable below.
// This variable must be present somewhere in your service worker file,
// even if you decide not to use precaching. See https://cra.link/PWA
precacheAndRoute(self.__WB_MANIFEST)

// Set up App Shell-style routing for React app routes only
// This excludes static pages managed by other programs
const fileExtensionRegexp = new RegExp('/[^/?]+\\.[^/]+$')
registerRoute(
  // Return false to exempt requests from being fulfilled by index.html.
  ({ request, url }: { request: Request; url: URL }) => {
    // If this isn't a navigation, skip.
    if (request.mode !== 'navigate') {
      return false
    }

    // If this is a URL that starts with /_, skip.
    if (url.pathname.startsWith('/_')) {
      return false
    }

    // Skip static pages - only handle root and React app routes
    // Allow other static pages (e.g., /en/, /docs/, etc.) to be served normally
    if (url.pathname !== '/' && !url.pathname.startsWith('/?')) {
      // If this is a static page path, let it pass through
      return false
    }

    // If this looks like a URL for a resource, because it contains
    // a file extension, skip.
    if (url.pathname.match(fileExtensionRegexp)) {
      return false
    }

    // Only handle root path and query parameters for React app
    return true
  },
  createHandlerBoundToURL(`${import.meta.env.BASE_URL}index.html`),
)

// An example runtime caching route for requests that aren't handled by the
// precache, in this case same-origin .png requests like those from in public/
registerRoute(
  // Add in any other file extensions or routing criteria as needed.
  ({ url }) =>
    url.origin === self.location.origin && url.pathname.endsWith('.png'),
  // Customize this strategy as needed, e.g., by changing to CacheFirst.
  new StaleWhileRevalidate({
    cacheName: 'images',
    plugins: [
      // Ensure that once this runtime cache reaches a maximum size the
      // least-recently used images are removed.
      new ExpirationPlugin({ maxEntries: 50 }),
    ],
  }),
)

// Enhanced message handling for skipWaiting and update management
self.addEventListener('message', (event) => {
  const { ports, data } = event

  if (!data || !data.type) {
    return
  }

  console.log('Service Worker: Received message:', data.type)

  if (data.type === 'SKIP_WAITING') {
    const replyPort = ports?.[0]

    if (replyPort) {
      // Handle with MessageChannel for better communication
      event.waitUntil(
        self.skipWaiting().then(
          () => {
            console.log('Service Worker: Skip waiting successful')
            replyPort.postMessage({ error: null, success: true })
          },
          (error) => {
            console.error('Service Worker: Skip waiting failed:', error)
            replyPort.postMessage({ error: error.message, success: false })
          },
        ),
      )
    } else {
      // Fallback for direct skipWaiting call
      console.log('Service Worker: Executing skipWaiting immediately')
      self.skipWaiting()
    }
  }

  // Handle other message types if needed
  if (data.type === 'GET_VERSION') {
    const replyPort = ports?.[0]
    if (replyPort) {
      // Send back current service worker version or timestamp
      replyPort.postMessage({
        version: __APP_VERSION__,
        timestamp: Date.now(),
        success: true,
      })
    }
  }
})

// Skip waiting to activate the new SW immediately.
// Users are notified via UpdateToast before page reload.
self.addEventListener('install', (event) => {
  console.log('Service Worker: Installing new version')
  event.waitUntil(self.skipWaiting())
})

// Enhanced activate event with cleanup
// Note: clientsClaim() is already called at the top level via workbox-core,
// so self.clients.claim() is not needed here.
self.addEventListener('activate', (event) => {
  console.log('Service Worker: Activating new version')

  const currentCachePrefix = 'workbox-precache-'

  event.waitUntil(
    // Clean up old caches that don't belong to the current service worker
    caches
      .keys()
      .then((cacheNames) => {
        return Promise.all(
          cacheNames.map((cacheName) => {
            // Keep current workbox precache and runtime caches
            if (cacheName === 'images') {
              return Promise.resolve()
            }
            if (
              cacheName.startsWith(currentCachePrefix) ||
              cacheName.startsWith('workbox-runtime')
            ) {
              console.log('Service Worker: Keeping cache:', cacheName)
              return Promise.resolve()
            }
            // Delete old/unknown caches
            console.log('Service Worker: Deleting old cache:', cacheName)
            return caches.delete(cacheName)
          }),
        )
      })
      .then(() => {
        // Notify all clients that the service worker has been updated
        return self.clients.matchAll().then((clients) => {
          clients.forEach((client) => {
            client.postMessage({
              type: 'SW_UPDATED',
              timestamp: Date.now(),
            })
          })
        })
      }),
  )
})

// Handle unhandled promise rejections
self.addEventListener('unhandledrejection', (_event) => {
  console.error('Service Worker: Unhandled promise rejection:', _event.reason)
})

console.log('Service Worker: Script loaded and ready')
